const PROCESSING_FEE = 5;
const COMPONENT_PREMIUM = 25;
const BLOCK_PREMIUM = 60;
const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const isComponent = (item: any): boolean => COMPONENT_TYPES.has(item.type);

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

const basePremium = (item: any): number => BASE_PREMIUMS[item.type] ?? 0;

const itemSurcharges = (item: any): number => {
  const base = basePremium(item);
  const cursedSurcharge = item.cursed ? base * 0.5 : 0;
  const enchantmentSurcharge = item.enchantment >= 5 ? base * 0.3 : 0;
  return cursedSurcharge + enchantmentSurcharge;
};

const totalComponentPremium = (items: any[]): number => {
  const components = items.filter(isComponent);
  const counts: Record<string, number> = {};
  for (const c of components) {
    counts[c.type] = (counts[c.type] ?? 0) + 1;
  }
  let total = 0;
  for (const count of Object.values(counts)) {
    if (count === 3) {
      total += BLOCK_PREMIUM;
    } else {
      total += count * COMPONENT_PREMIUM;
    }
  }
  return total;
};

export const processScenario = (scenario: any): any => {
  const results = scenario.steps.map((step: any) => {
    const mainItems = step.items.filter((i: any) => !isComponent(i));
    const mainBaseTotal = mainItems.reduce(
      (sum: number, item: any) => sum + basePremium(item),
      0,
    );
    const mainSurchargesTotal = mainItems.reduce(
      (sum: number, item: any) => sum + itemSurcharges(item),
      0,
    );
    const compTotal = totalComponentPremium(step.items);
    const policyBase = mainBaseTotal + compTotal;
    const firstInsurance = policyBase * 0.1;
    const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= 2 ? policyBase * 0.2 : 0;
    const premium = Math.ceil(PROCESSING_FEE + mainBaseTotal + mainSurchargesTotal + compTotal + firstInsurance - loyaltyDiscount);
    return { premium };
  });
  return { results };
};

